import { NativeQueryBuilder } from '../../query/NativeQueryBuilder.js';
/** @internal */
export class SqliteNativeQueryBuilder extends NativeQueryBuilder {
    compileTruncate() {
        const sql = `delete from ${this.getTableName()}`;
        this.parts.push(sql);
    }
    addLockClause() {
        return; // not supported
    }
}
